+    let placeholder = placeholder(mime_type, dims.map(|(w, _)| w), dims.map(|(_, h)| h));
+
+    if bytes.is_empty() {
+        return placeholder;
+    }
+
+    let cols = max_cols.max(1);
+    match protocol {
+        ImageProtocol::Kitty => {
+            let encoded = encode_kitty(bytes, cols);
+            if encoded.is_empty() {
